const validateIoTAddress = (ip) => {
  const localPatterns = [
    /^192\.168\.\d{1,3}\.\d{1,3}$/,
    /^10\.\d{1,3}\.\d{1,3}\.\d{1,3}$/,
    /^172\.(1[6-9]|2\d|3[01])\.\d{1,3}\.\d{1,3}$/,
  ];
  return localPatterns.some((pattern) => pattern.test(ip));
};

const buildIoTUrl = (ip, port = null, path = '', useHttps = false) => {
  const protocol = useHttps ? 'https' : 'http';
  const portStr = port ? `:${port}` : '';
  const cleanPath = path.startsWith('/') ? path : `/${path}`;
  return `${protocol}://${ip}${portStr}${cleanPath}`;
};

const iotRequest = async (deviceIp, path = '/', options = {}) => {
  const {
    method = 'GET',
    body = null,
    headers = {},
    port = null,
    useHttps = false,
    timeout = IOT_TIMEOUT,
    retries = 1,
    deviceAuth = null,
    parseResponse = true,
  } = options;

  if (!validateIoTAddress(deviceIp)) {
    throw new IoTDeviceError(
      `Invalid local network address: ${deviceIp}`,
      deviceIp,
      'INVALID_ADDRESS'
    );
  }

  const url = buildIoTUrl(deviceIp, port, path, useHttps);

  let requestConfig = {
    method,
    headers: {
      Accept: 'application/json',
      'Content-Type': 'application/json',
      ...headers,
    },
  };

  // Support various IoT auth schemes
  if (deviceAuth) {
    if (deviceAuth.type === 'basic') {
      const credentials = btoa(`${deviceAuth.username}:${deviceAuth.password}`);
      requestConfig.headers['Authorization'] = `Basic ${credentials}`;
    } else if (deviceAuth.type === 'bearer') {
      requestConfig.headers['Authorization'] = `Bearer ${deviceAuth.token}`;
    } else if (deviceAuth.type === 'apiKey') {
      requestConfig.headers[deviceAuth.headerName || 'X-API-Key'] = deviceAuth.key;
    }
  }

  if (body && method !== 'GET' && method !== 'HEAD') {
    requestConfig.body = typeof body === 'string' ? body : JSON.stringify(body);
  }

  log('info', `IoT ${method} ${url}`);

  const makeRequest = async () => {
    let response;
    try {
      response = await fetchWithTimeout(url, requestConfig, timeout);
    } catch (error) {
      if (error instanceof NetworkError && error.code === 'TIMEOUT') {
        throw new IoTDeviceError(
          `Device at ${deviceIp} did not respond within ${timeout}ms`,
          deviceIp,
          'DEVICE_TIMEOUT'
        );
      }
      throw new IoTDeviceError(
        `Cannot reach device at ${deviceIp}: ${error.message}`,
        deviceIp,
        'DEVICE_UNREACHABLE'
      );
    }

    if (!response.ok) {
      let responseBody = null;
      try {
        responseBody = await response.text();
      } catch (e) {
        // ignore
      }
      throw new IoTDeviceError(
        `Device returned status ${response.status}`,
        deviceIp,
        `HTTP_${response.status}`,
        responseBody
      );
    }

    if (!parseResponse) {
      return response;
    }

    const contentType = response.headers.get('content-type') || '';
    if (contentType.includes('application/json')) {
      const data = await response.json();
      log('info', `IoT Response from ${deviceIp}: OK`);
      return data;
    }

    const text = await response.text();
    // Try to parse as JSON anyway (some IoT devices don't set content-type)
    try {
      return JSON.parse(text);
    } catch (e) {
      return text;
    }
  };

  return retryRequest(makeRequest, retries, 500);
};

